import{_ as n,C as e,o as l,c as p,a2 as t,E as d}from"./chunks/framework.BnBoz4Zl.js";const i="/anjian-workbuddy-bluebook-site/assets/007_image_UNEqbRnJfo.DOMis77x.png",r="/anjian-workbuddy-bluebook-site/assets/008_image_L25tbHIUeo.bdit0dCN.png",y=JSON.parse('{"title":"第 17 章 结构化数据分析与可视化表达","description":"这一章只解决一个问题：手里有一堆乱数据，怎样让 WorkBuddy 帮你整理成能检查、能计算、能交付的结果。 不需要先学公式。跟着下面三个示例操作一次，就能掌握文本转表、单表清洗和多表对账。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 17 章 会议结束不是终点，工作才刚刚开始/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 17 章 会议结束不是终点，工作才刚刚开始/index.md","lastUpdated":1784771354000}'),o={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 17 章 会议结束不是终点，工作才刚刚开始/index.md"};function h(c,a,b,g,u,x){const s=e("MermaidDiagram");return l(),p("div",null,[a[0]||(a[0]=t('<h1 id="第-17-章-结构化数据分析与可视化表达" tabindex="-1">第 17 章 结构化数据分析与可视化表达 <a class="header-anchor" href="#第-17-章-结构化数据分析与可视化表达" aria-label="Permalink to &quot;第 17 章 结构化数据分析与可视化表达&quot;">​</a></h1><p>这一章只解决一个问题：<strong>手里有一堆乱数据，怎样让 WorkBuddy 帮你整理成能检查、能计算、能交付的结果。</strong></p><p>不需要先学公式。跟着下面三个示例操作一次，就能掌握文本转表、单表清洗和多表对账。</p><p>下面的练习样例均为合成数据，提示词均以可复制文本框呈现。</p><div class="warning custom-block"><p class="custom-block-title">先记住一条</p><p>不要把原文件直接交给 AI 覆盖。先复制一份，再让 WorkBuddy 生成新文件。真实工作中涉及个人信息、经营数据或财务口径时，还要先确认材料是否允许使用。</p></div><h2 id="_30-秒看懂本章" tabindex="-1">30 秒看懂本章 <a class="header-anchor" href="#_30-秒看懂本章" aria-label="Permalink to &quot;30 秒看懂本章&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你遇到的问题</th><th>跟做哪个示例</th><th>最后会得到什么</th></tr></thead><tbody><tr><td>群接龙格式乱、顺序乱</td><td>示例一</td><td>一张字段统一的报名表</td></tr><tr><td>日期、金额和渠道写法不统一</td><td>示例二</td><td>清洗后的表格、异常清单和核对说明</td></tr><tr><td>订单表与退款表需要合并</td><td>示例三</td><td>对账表、未匹配清单和净销售额</td></tr></tbody></table><p>第一次练习只要完成六步：</p>',8)),d(s,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E4%B8%8B%E8%BD%BD%E6%A0%B7%E4%BE%8B%5D%20--%3E%20B%5B%E6%94%BE%E8%BF%9B%E7%8B%AC%E7%AB%8B%E6%96%87%E4%BB%B6%E5%A4%B9%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%9C%A8%20WorkBuddy%20%E9%80%89%E6%8B%A9%E8%AF%A5%E6%96%87%E4%BB%B6%E5%A4%B9%5D%0A%20%20%20%20C%20--%3E%20D%5B%E5%A4%8D%E5%88%B6%E6%9C%AC%E7%AB%A0%E6%8F%90%E7%A4%BA%E8%AF%8D%5D%0A%20%20%20%20D%20--%3E%20E%5B%E7%A1%AE%E8%AE%A4%E8%A7%84%E5%88%99%E5%90%8E%E7%94%9F%E6%88%90%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20E%20--%3E%20F%5B%E6%8C%89%E6%A3%80%E6%9F%A5%E8%A1%A8%E9%AA%8C%E6%94%B6%5D%0A"}),a[1]||(a[1]=t(`<h2 id="开始前只做三件事" tabindex="-1">开始前只做三件事 <a class="header-anchor" href="#开始前只做三件事" aria-label="Permalink to &quot;开始前只做三件事&quot;">​</a></h2><ol><li>新建一个文件夹，例如 <code>第17章-数据清洗练习</code>。</li><li>把本章提供的样例下载到这个文件夹；练习自己的材料时，也只放副本。</li><li>打开 WorkBuddy，选择数据分析类任务，并把这个文件夹设为工作空间。产品入口可能随版本变化，以当前客户端为准。</li></ol><div class="tip custom-block"><p class="custom-block-title">文本框怎么用</p><p>下面深色文本框右上角有“复制”按钮。点击后粘贴到 WorkBuddy；文件名与实际文件不同时，只改文件名，不要删掉检查和验收要求。</p></div><h2 id="示例一-把群接龙整理成报名表" tabindex="-1">示例一：把群接龙整理成报名表 <a class="header-anchor" href="#示例一-把群接龙整理成报名表" aria-label="Permalink to &quot;示例一：把群接龙整理成报名表&quot;">​</a></h2><h3 id="_1-下载或复制样例" tabindex="-1">1. 下载或复制样例 <a class="header-anchor" href="#_1-下载或复制样例" aria-label="Permalink to &quot;1. 下载或复制样例&quot;">​</a></h3><p><a href="/anjian-workbuddy-bluebook-site/downloads/chapter-17/example-1-group-signup.txt">下载群接龙样例文本</a></p><p>原始内容故意混用了空格、逗号、句号、勾选符号和不同字段顺序：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 陈晨 运营 √ 不带 138****0001</span></span>
<span class="line"><span>2. 林晓，产品，参加，带1人，139****0002</span></span>
<span class="line"><span>3. 周宁。不到。研发。×。137****0003</span></span>
<span class="line"><span>4. 宋安 行政 136****0004 到 无</span></span></code></pre></div><h3 id="_2-复制提示词" tabindex="-1">2. 复制提示词 <a class="header-anchor" href="#_2-复制提示词" aria-label="Permalink to &quot;2. 复制提示词&quot;">​</a></h3><p><strong>复制提示词 1：群接龙转表</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请读取工作目录中的 example-1-group-signup.txt，把群接龙整理成 Excel 表格。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>固定列名和顺序：姓名、部门、联系电话、是否参加、是否带家属。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>统一规则：</span></span>
<span class="line"><span>1. “参加、去、到、√”统一为“参加”；</span></span>
<span class="line"><span>2. “不到、不参加、×”统一为“不参加”；</span></span>
<span class="line"><span>3. “不带、无、×”统一为“不带家属”；</span></span>
<span class="line"><span>4. “带、带1人”保留为“带1人”；</span></span>
<span class="line"><span>5. 联系电话只整理空格和连接符，不猜测缺失数字；</span></span>
<span class="line"><span>6. 无法判断的字段填写“待确认”，并另建“待确认清单”。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请生成 signup-clean.xlsx，不要修改原文本。</span></span>
<span class="line"><span>同时报告：总记录数、成功转换数、待确认数和采用的转换规则。</span></span></code></pre></div><h3 id="_3-对照预期结果" tabindex="-1">3. 对照预期结果 <a class="header-anchor" href="#_3-对照预期结果" aria-label="Permalink to &quot;3. 对照预期结果&quot;">​</a></h3><table tabindex="0"><thead><tr><th>姓名</th><th>部门</th><th>联系电话</th><th>是否参加</th><th>是否带家属</th></tr></thead><tbody><tr><td>陈晨</td><td>运营</td><td>138****0001</td><td>参加</td><td>不带家属</td></tr><tr><td>林晓</td><td>产品</td><td>139****0002</td><td>参加</td><td>带1人</td></tr><tr><td>周宁</td><td>研发</td><td>137****0003</td><td>不参加</td><td>不带家属</td></tr><tr><td>宋安</td><td>行政</td><td>136****0004</td><td>参加</td><td>不带家属</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">验收只看三点</p><ol><li>四条原文都进入结果表；2. 姓名、部门和电话没有串列；3. “是否参加”与“是否带家属”只出现规定值。</li></ol></div><p>如果有一行判断错了，不要手工改完就算。把错误告诉 WorkBuddy，让它按修正后的规则重新生成：</p><p><strong>复制提示词 2：发现错误后修正</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请不要直接改一个单元格后结束。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>先说明第 {行号} 行为什么判断错误；</span></span>
<span class="line"><span>把修正规则补充到规则清单；</span></span>
<span class="line"><span>再重新生成 signup-clean-v2.xlsx；</span></span>
<span class="line"><span>最后重新报告总记录数、成功转换数和待确认数。</span></span></code></pre></div><h2 id="示例二-清洗日期、金额和渠道名称" tabindex="-1">示例二：清洗日期、金额和渠道名称 <a class="header-anchor" href="#示例二-清洗日期、金额和渠道名称" aria-label="Permalink to &quot;示例二：清洗日期、金额和渠道名称&quot;">​</a></h2><h3 id="_1-下载样例表" tabindex="-1">1. 下载样例表 <a class="header-anchor" href="#_1-下载样例表" aria-label="Permalink to &quot;1. 下载样例表&quot;">​</a></h3><p><a href="/anjian-workbuddy-bluebook-site/downloads/chapter-17/example-2-sales-dirty.csv">下载业绩表清洗样例</a></p><p>原始数据中包含四种常见问题：日期格式不同、金额带单位、空行、渠道名称不统一。</p><table tabindex="0"><thead><tr><th>区域</th><th>原始日期</th><th>原始渠道</th><th>原始金额</th></tr></thead><tbody><tr><td>华北</td><td>2026/7/1</td><td>微信小店</td><td>1280元</td></tr><tr><td>华东</td><td>Jul-2</td><td>WeChat</td><td>980 元</td></tr><tr><td>华南</td><td>2026-07-03</td><td>微店</td><td>1,560元</td></tr><tr><td>华中</td><td>2026.07.04</td><td>小程序</td><td>760</td></tr></tbody></table><h3 id="_2-先检查-不直接开洗" tabindex="-1">2. 先检查，不直接开洗 <a class="header-anchor" href="#_2-先检查-不直接开洗" aria-label="Permalink to &quot;2. 先检查，不直接开洗&quot;">​</a></h3><p><strong>复制提示词 3：先做数据体检</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请只读检查 example-2-sales-dirty.csv，先不要生成清洗结果。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请报告：</span></span>
<span class="line"><span>1. 字段名、记录数和空行数；</span></span>
<span class="line"><span>2. 日期、金额和渠道列分别有哪些写法；</span></span>
<span class="line"><span>3. 哪些值可以按规则转换，哪些值存在歧义；</span></span>
<span class="line"><span>4. 拟采用的清洗规则；</span></span>
<span class="line"><span>5. 处理后准备生成哪些文件。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>已知条件：本表全部记录都属于 2026 年 7 月。</span></span>
<span class="line"><span>等我确认规则后再执行。</span></span></code></pre></div><p>看到规则没有问题后，回复第二段：</p><p><strong>复制提示词 4：确认规则并生成结果</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>确认按以下规则执行：</span></span>
<span class="line"><span>1. 日期统一为 YYYY-MM-DD；</span></span>
<span class="line"><span>2. 金额去掉“元”和千位分隔符，转成可计算的数值；</span></span>
<span class="line"><span>3. 删除完全空白的行，但不删除含部分空值的记录；</span></span>
<span class="line"><span>4. “微店、微信小店、WeChat”统一为“微店”；</span></span>
<span class="line"><span>5. 其他渠道名称保持原值；</span></span>
<span class="line"><span>6. 无法可靠转换的记录放进异常清单，不要猜测。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请生成：</span></span>
<span class="line"><span>- clean-sales.csv：清洗后的数据；</span></span>
<span class="line"><span>- exception-list.csv：异常与待确认记录；</span></span>
<span class="line"><span>- reconciliation.md：处理前后行数、金额合计和分类数量核对。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不要覆盖原文件。</span></span></code></pre></div><h3 id="_3-对照预期结果-1" tabindex="-1">3. 对照预期结果 <a class="header-anchor" href="#_3-对照预期结果-1" aria-label="Permalink to &quot;3. 对照预期结果&quot;">​</a></h3><table tabindex="0"><thead><tr><th>区域</th><th>日期</th><th>渠道</th><th style="text-align:right;">金额</th></tr></thead><tbody><tr><td>华北</td><td>2026-07-01</td><td>微店</td><td style="text-align:right;">1280</td></tr><tr><td>华东</td><td>2026-07-02</td><td>微店</td><td style="text-align:right;">980</td></tr><tr><td>华南</td><td>2026-07-03</td><td>微店</td><td style="text-align:right;">1560</td></tr><tr><td>华中</td><td>2026-07-04</td><td>小程序</td><td style="text-align:right;">760</td></tr></tbody></table><p><img src="`+i+`" alt="合成示例：WorkBuddy 生成清洗结果、异常清单和核对报告" loading="lazy"></p><p><em>图 17-1　合成演示：结果不应只有一张“干净表”，还应同时保留异常清单和核对报告。</em></p><div class="tip custom-block"><p class="custom-block-title">验收只看四点</p><ol><li>日期都能按日期排序；2. 金额列可以直接求和；3. 渠道只保留“微店”和“小程序”；4. 原文件仍然存在且没有被覆盖。</li></ol></div><h2 id="示例三-合并订单表与退款表" tabindex="-1">示例三：合并订单表与退款表 <a class="header-anchor" href="#示例三-合并订单表与退款表" aria-label="Permalink to &quot;示例三：合并订单表与退款表&quot;">​</a></h2><h3 id="_1-下载两张样例表" tabindex="-1">1. 下载两张样例表 <a class="header-anchor" href="#_1-下载两张样例表" aria-label="Permalink to &quot;1. 下载两张样例表&quot;">​</a></h3><ul><li><a href="/anjian-workbuddy-bluebook-site/downloads/chapter-17/example-3-orders.csv">下载订单表示例</a></li><li><a href="/anjian-workbuddy-bluebook-site/downloads/chapter-17/example-3-refunds.csv">下载退款表示例</a></li></ul><p>这组数据故意放入三个坑：重复订单号、订单表中的负数冲正、退款表中的未匹配订单。</p><p><strong>订单表</strong></p><table tabindex="0"><thead><tr><th>订单号</th><th style="text-align:right;">销售额</th><th>状态</th></tr></thead><tbody><tr><td>ORD-001</td><td style="text-align:right;">1000</td><td>已完成</td></tr><tr><td>ORD-002</td><td style="text-align:right;">800</td><td>已完成</td></tr><tr><td>ORD-003</td><td style="text-align:right;">500</td><td>已完成</td></tr><tr><td>ORD-003</td><td style="text-align:right;">-500</td><td>退货冲正</td></tr></tbody></table><p><strong>退款表</strong></p><table tabindex="0"><thead><tr><th>退款单号</th><th>订单号</th><th style="text-align:right;">退款额</th><th>状态</th></tr></thead><tbody><tr><td>RF-001</td><td>ORD-003</td><td style="text-align:right;">500</td><td>已退款</td></tr><tr><td>RF-002</td><td>ORD-004</td><td style="text-align:right;">120</td><td>未匹配示例</td></tr></tbody></table><h3 id="_2-第一轮只找风险" tabindex="-1">2. 第一轮只找风险 <a class="header-anchor" href="#_2-第一轮只找风险" aria-label="Permalink to &quot;2. 第一轮只找风险&quot;">​</a></h3><p><strong>复制提示词 5：检查合并关系和重复扣减风险</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请只读检查 example-3-orders.csv 和 example-3-refunds.csv，先不要生成最终对账表。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请回答：</span></span>
<span class="line"><span>1. 两表分别有多少行，订单号是否唯一；</span></span>
<span class="line"><span>2. 哪些订单是一对一、一对多或未匹配；</span></span>
<span class="line"><span>3. 订单表中是否存在负数冲正；</span></span>
<span class="line"><span>4. 同一订单是否同时出现负数冲正和退款记录；</span></span>
<span class="line"><span>5. 如果直接使用“销售额 - 退款额”，哪些订单可能被重复扣减；</span></span>
<span class="line"><span>6. 需要我确认哪些业务规则。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不要自行决定负数冲正和退款记录的优先级。</span></span></code></pre></div><p>WorkBuddy 应指出：<code>ORD-003</code> 同时有 <code>-500</code> 冲正和 <code>500</code> 退款，直接再减一次退款会重复扣减；<code>ORD-004</code> 在订单表中找不到，应进入未匹配清单。</p><h3 id="_3-第二轮确认本练习口径" tabindex="-1">3. 第二轮确认本练习口径 <a class="header-anchor" href="#_3-第二轮确认本练习口径" aria-label="Permalink to &quot;3. 第二轮确认本练习口径&quot;">​</a></h3><p>真实工作必须由业务人员确认规则。本练习统一采用：订单表中的负数冲正已经代表退款；金额一致的退款记录只作为核对证据，不再减一次。</p><p><strong>复制提示词 6：按确认口径生成对账结果</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>按以下已确认规则生成结果：</span></span>
<span class="line"><span>1. 订单表中的负数冲正已经计入退款影响；</span></span>
<span class="line"><span>2. 同一订单在退款表出现相同金额时，只标记“已核对”，不重复扣减；</span></span>
<span class="line"><span>3. 退款表中找不到原订单的记录进入“未匹配退款清单”；</span></span>
<span class="line"><span>4. 净销售额按订单表的正数销售额与负数冲正合计；</span></span>
<span class="line"><span>5. 不删除重复记录，保留来源并说明合并关系。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请生成：</span></span>
<span class="line"><span>- order-refund-reconciliation.xlsx：逐订单对账明细；</span></span>
<span class="line"><span>- unmatched-refunds.xlsx：未匹配退款；</span></span>
<span class="line"><span>- reconciliation.md：行数、匹配关系、异常数量和金额核对。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>确认金额差异可以解释后，再给出结论。不要覆盖两张原表。</span></span></code></pre></div><h3 id="_4-对照预期结果" tabindex="-1">4. 对照预期结果 <a class="header-anchor" href="#_4-对照预期结果" aria-label="Permalink to &quot;4. 对照预期结果&quot;">​</a></h3><table tabindex="0"><thead><tr><th>订单号</th><th style="text-align:right;">正数销售额</th><th style="text-align:right;">负数冲正</th><th style="text-align:right;">退款记录</th><th>处理结果</th><th style="text-align:right;">净销售额</th></tr></thead><tbody><tr><td>ORD-001</td><td style="text-align:right;">1000</td><td style="text-align:right;">0</td><td style="text-align:right;">0</td><td>正常</td><td style="text-align:right;">1000</td></tr><tr><td>ORD-002</td><td style="text-align:right;">800</td><td style="text-align:right;">0</td><td style="text-align:right;">0</td><td>正常</td><td style="text-align:right;">800</td></tr><tr><td>ORD-003</td><td style="text-align:right;">500</td><td style="text-align:right;">-500</td><td style="text-align:right;">500</td><td>退款已核对，不重复扣减</td><td style="text-align:right;">0</td></tr><tr><td>ORD-004</td><td style="text-align:right;">0</td><td style="text-align:right;">0</td><td style="text-align:right;">120</td><td>未匹配，待确认</td><td style="text-align:right;">-</td></tr></tbody></table><p><img src="`+r+`" alt="合成示例：多表处理后的数据质量与金额核对报告" loading="lazy"></p><p><em>图 17-2　合成演示：核对报告应同时展示源表行数、异常数量、处理后行数和金额差异。图中使用区域业绩合并演示报告形式。</em></p><div class="tip custom-block"><p class="custom-block-title">验收只看四点</p><ol><li><code>ORD-003</code> 没有被扣两次；2. <code>ORD-004</code> 没有被偷偷删除；3. 每条结果能回到订单表或退款表；4. 净销售额公式写进核对说明。</li></ol></div><h2 id="最后一步-数字确认后再画图" tabindex="-1">最后一步：数字确认后再画图 <a class="header-anchor" href="#最后一步-数字确认后再画图" aria-label="Permalink to &quot;最后一步：数字确认后再画图&quot;">​</a></h2><p>只有明细、行数和金额已经核对，才复制下面的提示词生成图表。</p><p><strong>复制提示词 7：生成汇总和图表</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请基于已经确认无误的处理结果生成汇总表和图表。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>先输出汇总表供我复核，再生成图表：</span></span>
<span class="line"><span>1. 记录数与异常数对比；</span></span>
<span class="line"><span>2. 分类或渠道构成；</span></span>
<span class="line"><span>3. 金额或数量趋势；</span></span>
<span class="line"><span>4. 未匹配、重复和待确认记录数量。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每张图必须写明标题、单位、时间范围、样本量和数据更新时间。</span></span>
<span class="line"><span>每条结论必须引用具体汇总指标，并说明缺失值和限制。</span></span>
<span class="line"><span>不得根据相关性推断因果，不得隐藏异常或小样本。</span></span></code></pre></div><h2 id="换成自己的文件时-只改这几处" tabindex="-1">换成自己的文件时，只改这几处 <a class="header-anchor" href="#换成自己的文件时-只改这几处" aria-label="Permalink to &quot;换成自己的文件时，只改这几处&quot;">​</a></h2><table tabindex="0"><thead><tr><th>占位内容</th><th>改成什么</th></tr></thead><tbody><tr><td><code>example-*.csv</code></td><td>你的实际文件名</td></tr><tr><td>固定列名</td><td>你希望输出的字段和顺序</td></tr><tr><td>同义词规则</td><td>你的分类名称对照</td></tr><tr><td>唯一键或合并键</td><td>订单号、编号等已确认字段</td></tr><tr><td>计算规则</td><td>经业务人员确认的公式和口径</td></tr><tr><td>输出文件名</td><td>你希望交付的文件名</td></tr></tbody></table><p>不要删除这些句子：</p><ul><li>先检查，等我确认后再执行。</li><li>不要覆盖原文件。</li><li>无法判断的内容标记“待确认”。</li><li>输出处理前后的行数和金额核对。</li></ul><h2 id="常见弯路-结果不对时怎么处理" tabindex="-1">常见弯路：结果不对时怎么处理 <a class="header-anchor" href="#常见弯路-结果不对时怎么处理" aria-label="Permalink to &quot;常见弯路：结果不对时怎么处理&quot;">​</a></h2><h3 id="workbuddy-直接开始生成-没有等确认" tabindex="-1">WorkBuddy 直接开始生成，没有等确认 <a class="header-anchor" href="#workbuddy-直接开始生成-没有等确认" aria-label="Permalink to &quot;WorkBuddy 直接开始生成，没有等确认&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请停止生成结果，回到只读检查阶段。</span></span>
<span class="line"><span>先输出字段、行数、空值、重复值、异常和拟采用规则；等我回复“确认”后再生成新文件。</span></span></code></pre></div><h3 id="结果看起来整齐-但不知道数字对不对" tabindex="-1">结果看起来整齐，但不知道数字对不对 <a class="header-anchor" href="#结果看起来整齐-但不知道数字对不对" aria-label="Permalink to &quot;结果看起来整齐，但不知道数字对不对&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请补充处理前后核对报告：原始行数、结果行数、删除数、去重数、异常数、未匹配数、关键金额合计和差异原因。无法解释的差异标记为“待确认”。</span></span></code></pre></div><h3 id="模型擅自猜了日期、类别或负责人" tabindex="-1">模型擅自猜了日期、类别或负责人 <a class="header-anchor" href="#模型擅自猜了日期、类别或负责人" aria-label="Permalink to &quot;模型擅自猜了日期、类别或负责人&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请撤销所有没有明确来源的推断。把无法从原始材料确认的值改为“待确认”，单独输出记录位置、原值、缺失字段和需要人工回答的问题。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>输入材料是否合法、完整并允许用于本次处理。</li><li>字段含义、分类映射、唯一键和去重条件是否正确。</li><li>负数、冲正、退款、跨期和未匹配记录如何处理。</li><li>处理前后的行数、金额和分类数量能否解释。</li><li>结果是否可能泄露个人信息或未公开经营数据。</li></ul><h2 id="安全边界" tabindex="-1">安全边界 <a class="header-anchor" href="#安全边界" aria-label="Permalink to &quot;安全边界&quot;">​</a></h2><ul><li>不向未批准的外部服务上传敏感表格、个人信息和未公开经营数据。</li><li>不把模型推断当作业务事实、财务结论或管理决定。</li><li>不自动删除原始记录、覆盖源文件、外发结果或提交审批。</li><li>对小样本、自由文本和联系方式做脱敏或限制访问。</li><li>产品入口、界面和能力可能随版本变化，以当前客户端和官方说明为准。</li></ul>`,73))])}const m=n(o,[["render",h]]);export{y as __pageData,m as default};
